import ast
import re

def analyze_generated_code(code: str) -> dict:
    tree = ast.parse(code)
    issues = []

    # Detect dangerous operations without try/except
    for node in ast.walk(tree):
        if isinstance(node, ast.Call):
            if getattr(node.func, 'id', '') in ['open', 'exec', 'eval', 'subprocess.run']:
                parent = ast.ParentMap(ast.parse(code))[node]
                if not any(isinstance(p, ast.Try) for p in ast.walk(parent)):
                    issues.append(f'Dangerous {node.func.id} without try/except')

    # Detect missing input validation
    if re.search(r'\b(input|sys.argv|request.args)\b', code) and 'if' not in code:
        issues.append('Missing input validation')

    return {'safe': len(issues) == 0, 'issues': issues}

