from smolagents import ToolAgent, Tool
from pydantic import BaseModel, ValidationError

class SafeFileReader(Tool):
    name = 'safe_file_reader'
    description = 'Read file safely with size limits'

    class Input(BaseModel):
        path: str
        max_bytes: int = 1024

    def call(self, path: str, max_bytes: int = 1024) -> str:
        try:
            # Schema validation
            input_data = self.Input(path=path, max_bytes=max_bytes)

            # Security checks
            if not path.startswith('/tmp/'):
                raise ValueError('Only /tmp/ files allowed')

            with open(path, 'r') as f:
                content = f.read(max_bytes)
                return f'Read {len(content)} bytes successfully'
        except (FileNotFoundError, PermissionError) as e:
            return f'File access failed safely: {str(e)}'
        except ValidationError as e:
            return f'Invalid parameters: {e.errors()}'

from smolagents import Conversation
from typing import Dict, Any

class ResilientConversation(Conversation):
    def __init__(self):
        super().__init__()
        self.checkpoints: Dict[str, Any] = {}

    def run_with_recovery(self, step: str, checkpoint_key: str = None) -> dict:
        try:
            result = self.run(step)

            # Auto-checkpoint successful steps
            if checkpoint_key:
                self.checkpoints[checkpoint_key] = result

            return {'success': True, 'result': result}

        except Exception as e:
            # Recovery: restore from last checkpoint
            if checkpoint_key and checkpoint_key in self.checkpoints:
                recovery_prompt = f'Previous step failed: {str(e)}. Continuing from: {self.checkpoints[checkpoint_key]}. Current task: {step}'
                recovery_result = self.run(recovery_prompt)
                return {'success': True, 'recovered': True, 'result': recovery_result}

            return {'success': False, 'error': str(e), 'recovered': False}
